import math

def minimum_product_subset(arr):
    n = len(arr)
    if n == 0:
        return 0 

    neg_count = 0
    zero_count = 0
    prod_so_far = 1
    max_neg = float('-inf')
    min_pos = float('inf')

    for x in arr:
        if x == 0:
            zero_count += 1
        elif x < 0:
            neg_count += 1
            prod_so_far *= x
            max_neg = max(max_neg, x)
        else:
            prod_so_far *= x
            min_pos = min(min_pos, x)

    if neg_count == 0:
        if zero_count > 0:
            return 0
        else:
            return min_pos
    else:
        if neg_count % 2 == 1:
            return prod_so_far
        else:
            return prod_so_far // max_neg
